import { useMemo, useState } from 'react';
import { createColumnHelper } from '@tanstack/react-table';
import type { AuditLog } from '../../types/domain.types';
import { DataTable } from '../ui/table';
import { StatusBadge } from '../ui/status-badge';

const col = createColumnHelper<AuditLog>();
const DATE_FMT = new Intl.DateTimeFormat('he-IL', { dateStyle: 'short', timeStyle: 'short' });

const TABLE_LABELS: Record<string, string> = {
  factories:              'מפעלים',
  supervisors:            'מפקחים',
  jobs:                   'עבודות',
  financial_events:       'אירועים פיננסיים',
  flex_field_definitions: 'שדות גמישים',
};

function JsonViewer({ value }: { value: Record<string, unknown> | null }) {
  const [open, setOpen] = useState(false);
  if (!value) return <span style={{ color: '#94a3b8' }}>—</span>;
  return (
    <span>
      <button
        className="btn btn-ghost btn-sm"
        style={{ padding: '2px 6px', fontSize: 11 }}
        onClick={() => setOpen(o => !o)}
      >
        {open ? 'הסתר' : 'הצג'}
      </button>
      {open && (
        <pre style={{ fontSize: 11, background: '#f8fafc', padding: 8, borderRadius: 4, marginTop: 4, maxWidth: 400, overflowX: 'auto', whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}>
          {JSON.stringify(value, null, 2)}
        </pre>
      )}
    </span>
  );
}

interface AuditLogTableProps {
  logs: readonly AuditLog[];
  loading: boolean;
}

export function AuditLogTable({ logs, loading }: AuditLogTableProps) {
  const columns = useMemo(() => [
    col.accessor('created_at', {
      header: 'תאריך',
      cell:   i => DATE_FMT.format(new Date(i.getValue())),
    }),
    col.accessor('operation', {
      header: 'פעולה',
      cell:   i => <StatusBadge value={i.getValue()} />,
    }),
    col.accessor('table_name', {
      header: 'טבלה',
      cell:   i => TABLE_LABELS[i.getValue()] ?? i.getValue(),
    }),
    col.accessor('actor_id', {
      header: 'משתמש',
      cell:   i => {
        const v = i.getValue();
        return v.length > 20 ? v.slice(0, 8) + '…' : v;
      },
    }),
    col.accessor('old_values', {
      header: 'לפני',
      cell:   i => <JsonViewer value={i.getValue() as Record<string, unknown> | null} />,
    }),
    col.accessor('new_values', {
      header: 'אחרי',
      cell:   i => <JsonViewer value={i.getValue() as Record<string, unknown> | null} />,
    }),
  ], []);

  return (
    <DataTable
      data={logs as AuditLog[]}
      columns={columns}
      loading={loading}
      emptyMessage="אין רשומות."
    />
  );
}
