import { useState } from 'react';
import { ErrorBanner } from '../components/ui/error-banner';
import { FinancialEventsTable } from '../components/financial-events/financial-events-table';
import { useFinancialEventLedger } from '../hooks/use-financial-events';
import { FinancialEventType } from '../types/enums';
import type { FinancialEventWithJobCode } from '../types/domain.types';

const ILS = new Intl.NumberFormat('he-IL', { style: 'currency', currency: 'ILS' });
const CREDIT_TYPES = new Set<string>(['Credit', 'Debt_Close', 'Offset']);

function computeSummary(events: readonly FinancialEventWithJobCode[]) {
  let charges = 0;
  let credits  = 0;
  for (const e of events) {
    if (CREDIT_TYPES.has(e.event_type)) credits  += e.amount;
    else                                 charges += e.amount;
  }
  return { charges, credits, balance: credits - charges };
}

export function LedgerPage() {
  const [eventTypeFilter, setEventTypeFilter] = useState('');
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo,   setDateTo]   = useState('');

  const { state, reload } = useFinancialEventLedger({
    ...(eventTypeFilter ? { eventType: eventTypeFilter as FinancialEventType } : {}),
    ...(dateFrom ? { dateFrom: new Date(dateFrom).toISOString() }          : {}),
    ...(dateTo   ? { dateTo:   new Date(dateTo + 'T23:59:59').toISOString() } : {}),
  });

  const events  = state.status === 'success' ? state.data.items : [];
  const total   = state.status === 'success' ? state.data.total_count : 0;
  const loading = state.status === 'idle' || state.status === 'loading';

  const { charges, credits, balance } = computeSummary(events);

  return (
    <div className="page">
      <div className="page-header">
        <h1>ספר חשבונות פיננסי</h1>
        <button className="btn btn-ghost" onClick={reload} disabled={loading}>
          רענן
        </button>
      </div>

      {state.status === 'error' && <ErrorBanner error={state.error} />}

      <div className="filters">
        <select
          className="filter-select"
          value={eventTypeFilter}
          onChange={e => setEventTypeFilter(e.target.value)}
        >
          <option value="">כל הסוגים</option>
          {Object.values(FinancialEventType).map(v => (
            <option key={v} value={v}>{v.replace(/_/g, ' ')}</option>
          ))}
        </select>

        <label style={{ fontSize: 12, color: '#64748b', display: 'flex', alignItems: 'center', gap: 6 }}>
          מתאריך
          <input
            type="date"
            className="filter-input"
            style={{ width: 130 }}
            value={dateFrom}
            onChange={e => setDateFrom(e.target.value)}
          />
        </label>

        <label style={{ fontSize: 12, color: '#64748b', display: 'flex', alignItems: 'center', gap: 6 }}>
          עד תאריך
          <input
            type="date"
            className="filter-input"
            style={{ width: 130 }}
            value={dateTo}
            onChange={e => setDateTo(e.target.value)}
          />
        </label>

        {(eventTypeFilter || dateFrom || dateTo) && (
          <button
            className="btn btn-ghost btn-sm"
            onClick={() => { setEventTypeFilter(''); setDateFrom(''); setDateTo(''); }}
          >
            נקה
          </button>
        )}
      </div>

      {!loading && (
        <div className="ledger-summary">
          <div className="ledger-summary-card ledger-debit">
            <span className="ledger-summary-label">חיובים</span>
            <span className="ledger-summary-value">{ILS.format(charges)}</span>
          </div>
          <div className="ledger-summary-card ledger-credit">
            <span className="ledger-summary-label">זיכויים</span>
            <span className="ledger-summary-value">{ILS.format(credits)}</span>
          </div>
          <div className={`ledger-summary-card ledger-balance ${balance >= 0 ? 'ledger-balance-pos' : 'ledger-balance-neg'}`}>
            <span className="ledger-summary-label">יתרה</span>
            <span className="ledger-summary-value">{ILS.format(balance)}</span>
          </div>
          <div className="ledger-summary-card ledger-count">
            <span className="ledger-summary-label">רשומות</span>
            <span className="ledger-summary-value">{total}</span>
          </div>
        </div>
      )}

      <FinancialEventsTable events={events} loading={loading} />
    </div>
  );
}
