import { useState } from 'react';
import { ErrorBanner } from '../components/ui/error-banner';
import { AuditLogTable } from '../components/audit/audit-log-table';
import { useAuditLogs } from '../hooks/use-audit-logs';

const TABLES = ['factories', 'supervisors', 'jobs', 'financial_events', 'flex_field_definitions'];
const TABLE_LABELS: Record<string, string> = {
  factories:              'מפעלים',
  supervisors:            'מפקחים',
  jobs:                   'עבודות',
  financial_events:       'אירועים פיננסיים',
  flex_field_definitions: 'שדות גמישים',
};

type Operation = 'INSERT' | 'UPDATE' | 'DELETE';

export function AuditLogPage() {
  const [tableFilter, setTableFilter]     = useState('');
  const [opFilter,    setOpFilter]        = useState('');
  const [dateFrom,    setDateFrom]        = useState('');
  const [dateTo,      setDateTo]          = useState('');

  const { state, reload } = useAuditLogs({
    ...(tableFilter ? { tableName:  tableFilter }                                       : {}),
    ...(opFilter    ? { operation:  opFilter as Operation }                              : {}),
    ...(dateFrom    ? { dateFrom:   new Date(dateFrom).toISOString() }                  : {}),
    ...(dateTo      ? { dateTo:     new Date(dateTo + 'T23:59:59').toISOString() }      : {}),
  });

  const logs    = state.status === 'success' ? state.data.items : [];
  const total   = state.status === 'success' ? state.data.total_count : 0;
  const loading = state.status === 'idle' || state.status === 'loading';

  const hasFilter = tableFilter || opFilter || dateFrom || dateTo;

  return (
    <div className="page">
      <div className="page-header">
        <h1>יומן ביקורת {!loading && <span style={{ fontSize: 14, fontWeight: 400, color: '#64748b' }}>({total} רשומות)</span>}</h1>
        <button className="btn btn-ghost" onClick={reload} disabled={loading}>רענן</button>
      </div>

      {state.status === 'error' && <ErrorBanner error={state.error} />}

      <div className="filters">
        <select
          className="filter-select"
          value={tableFilter}
          onChange={e => setTableFilter(e.target.value)}
        >
          <option value="">כל הטבלאות</option>
          {TABLES.map(t => (
            <option key={t} value={t}>{TABLE_LABELS[t] ?? t}</option>
          ))}
        </select>

        <select
          className="filter-select"
          value={opFilter}
          onChange={e => setOpFilter(e.target.value)}
        >
          <option value="">כל הפעולות</option>
          <option value="INSERT">יצירה</option>
          <option value="UPDATE">עדכון</option>
          <option value="DELETE">מחיקה</option>
        </select>

        <label style={{ fontSize: 12, color: '#64748b', display: 'flex', alignItems: 'center', gap: 6 }}>
          מתאריך
          <input
            type="date"
            className="filter-input"
            style={{ width: 130 }}
            value={dateFrom}
            onChange={e => setDateFrom(e.target.value)}
          />
        </label>

        <label style={{ fontSize: 12, color: '#64748b', display: 'flex', alignItems: 'center', gap: 6 }}>
          עד תאריך
          <input
            type="date"
            className="filter-input"
            style={{ width: 130 }}
            value={dateTo}
            onChange={e => setDateTo(e.target.value)}
          />
        </label>

        {hasFilter && (
          <button
            className="btn btn-ghost btn-sm"
            onClick={() => { setTableFilter(''); setOpFilter(''); setDateFrom(''); setDateTo(''); }}
          >
            נקה
          </button>
        )}
      </div>

      <AuditLogTable logs={logs} loading={loading} />
    </div>
  );
}
