type BadgeVariant = 'gray' | 'yellow' | 'green' | 'red' | 'blue' | 'purple' | 'dark';

const COLOR_MAP: Record<string, BadgeVariant> = {
  // Operational statuses
  Draft:          'gray',
  Waiting_Match:  'yellow',
  Partial_Match:  'yellow',
  Matched:        'green',
  Cancelled:      'red',
  // Accounting statuses
  Pending_Approval:   'gray',
  Approved:           'blue',
  Queued_For_MASAV:   'purple',
  Paid:               'green',
  Closed:             'dark',
  // Factory / supervisor statuses
  Active:             'green',
  Inactive:           'gray',
  Archived:           'dark',
  // Financial event types
  Debit:              'red',
  Credit:             'green',
  Adjustment:         'yellow',
  Fee:                'yellow',
  Reversal:           'purple',
  // Payment methods / terms
  MASAV:              'blue',
  Check:              'gray',
  Wire:               'blue',
  Cash:               'dark',
  Net_30:             'gray',
  Net_60:             'gray',
  Net_90:             'gray',
  Immediate:          'green',
};

interface StatusBadgeProps {
  value: string;
}

export function StatusBadge({ value }: StatusBadgeProps) {
  const variant: BadgeVariant = COLOR_MAP[value] ?? 'gray';
  const label = value.replace(/_/g, ' ');
  return <span className={`badge badge-${variant}`}>{label}</span>;
}
