import { useCallback, useEffect, useState } from 'react';
import { useRepositories } from '../contexts/repository.context';
import type { AuditLog, PaginatedResult } from '../types/domain.types';
import type { AsyncState } from '../types/async.types';

export function useAuditLogs(params: {
  tableName?: string | undefined;
  operation?: 'INSERT' | 'UPDATE' | 'DELETE' | undefined;
  dateFrom?:  string | undefined;
  dateTo?:    string | undefined;
  limit?:     number | undefined;
  offset?:    number | undefined;
} = {}) {
  const repos = useRepositories();
  const [state, setState] = useState<AsyncState<PaginatedResult<AuditLog>>>({ status: 'idle' });
  const [epoch, setEpoch] = useState(0);

  const { tableName, operation, dateFrom, dateTo, limit, offset } = params;

  useEffect(() => {
    let cancelled = false;
    setState({ status: 'loading' });
    repos.auditLogs.list({ tableName, operation, dateFrom, dateTo, limit, offset }).then(result => {
      if (cancelled) return;
      if (result.error !== null) setState({ status: 'error', error: result.error });
      else                        setState({ status: 'success', data: result.data });
    });
    return () => { cancelled = true; };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [repos, tableName, operation, dateFrom, dateTo, limit, offset, epoch]);

  const reload = useCallback(() => setEpoch(e => e + 1), []);
  return { state, reload };
}
