import { BaseRepository } from './base.repository';
import type { AuditLog, PaginatedResult, RpcResponse } from '../../types/domain.types';

export class AuditLogsRepository extends BaseRepository {
  async list(params: {
    tableName?: string | undefined;
    operation?: 'INSERT' | 'UPDATE' | 'DELETE' | undefined;
    dateFrom?:  string | undefined;
    dateTo?:    string | undefined;
    limit?:     number | undefined;
    offset?:    number | undefined;
  } = {}): Promise<RpcResponse<PaginatedResult<AuditLog>>> {
    return this.callReadRpc<PaginatedResult<AuditLog>>(
      'rpc_list_audit_logs',
      {
        p_table_name: params.tableName ?? null,
        p_operation:  params.operation ?? null,
        p_date_from:  params.dateFrom  ?? null,
        p_date_to:    params.dateTo    ?? null,
        p_limit:      params.limit  ?? 100,
        p_offset:     params.offset ?? 0,
      },
    );
  }
}
