import { useMemo } from 'react';
import { createColumnHelper } from '@tanstack/react-table';
import type { FinancialEventWithJobCode } from '../../types/domain.types';
import { DataTable } from '../ui/table';
import { StatusBadge } from '../ui/status-badge';

const col = createColumnHelper<FinancialEventWithJobCode>();
const ILS = new Intl.NumberFormat('he-IL', { style: 'currency', currency: 'ILS' });
const DATE_FMT = new Intl.DateTimeFormat('he-IL', { dateStyle: 'short', timeStyle: 'short' });

const CREDIT_TYPES = new Set(['Credit', 'Debt_Close', 'Offset']);

interface FinancialEventsTableProps {
  events: readonly FinancialEventWithJobCode[];
  loading: boolean;
}

export function FinancialEventsTable({ events, loading }: FinancialEventsTableProps) {
  const columns = useMemo(() => [
    col.accessor('created_at', {
      header: 'תאריך',
      cell:   i => DATE_FMT.format(new Date(i.getValue())),
    }),
    col.accessor('event_type', {
      header: 'סוג אירוע',
      cell:   i => <StatusBadge value={i.getValue()} />,
    }),
    col.accessor('job_code', { header: 'קוד עבודה' }),
    col.accessor('amount', {
      header: 'סכום',
      cell:   i => {
        const isCredit = CREDIT_TYPES.has(i.row.original.event_type);
        return (
          <span style={{ color: isCredit ? '#166534' : '#991b1b', fontWeight: 500 }}>
            {isCredit ? '+' : '-'}{ILS.format(i.getValue())}
          </span>
        );
      },
    }),
    col.accessor('description', {
      header: 'תיאור',
      cell:   i => i.getValue() ?? '—',
    }),
  ], []);

  return (
    <DataTable
      data={events as FinancialEventWithJobCode[]}
      columns={columns}
      loading={loading}
      emptyMessage="אין אירועים פיננסיים."
    />
  );
}
